('chunk_a20bbdf1a2f933129e','file_fcd18e24135890ff64','00-index.md','The IB teaching contract (applies to every file)','Teach for: inquiry · conceptual understanding · critical thinking · real-world application · reflection · international-mindedness · creativity · independent learning. Explain in five layers (age-10 → classroom → MYP → cross-subject → advanced). Ask before telling. Surface misconceptions before assessing. Connect across subjects. Reflect after every topic. Reinforce with a 3-sentence summary, one application, one challenge, one memory trick, one revision tip. Success = the student can understand, explain, apply, analyse, evaluate, create, teach someone else, and use knowledge confidently in unfamiliar situations.

*Source syllabus: "IISH MYP Grade 7 – Syllabus Focus, 2026–2027."*','{"2026":1,"2027":1,"the":2,"teaching":1,"contract":1,"applies":1,"every":2,"file":1,"teach":2,"for":1,"inquiry":1,"conceptual":1,"understanding":1,"critical":1,"thinking":1,"real":1,"world":1,"application":2,"reflection":1,"international":1,"mindedness":1,"creativity":1,"independent":1,"learning":1,"explain":2,"five":1,"layers":1,"age":1,"classroom":1,"myp":2,"cross":1,"subject":1,"advanced":1,"ask":1,"before":2,"telling":1,"surface":1,"misconceptions":1,"assessing":1,"connect":1,"across":1,"subjects":1,"reflect":1,"after":1,"topic":1,"reinforce":1,"with":1,"sentence":1,"summary":1,"one":4,"challenge":1,"memory":1,"trick":1,"revision":1,"tip":1,"success":1,"student":1,"can":1,"understand":1,"apply":1,"analyse":1,"evaluate":1,"create":1,"someone":1,"else":1,"and":1,"use":1,"knowledge":1,"confidently":1,"unfamiliar":1,"situations":1,"source":1,"syllabus":2,"iish":1,"grade":1,"focus":1}'::jsonb),
